#!/usr/bin/env python3
import sys
out = []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    x = int(line)
    out.append("Yes" if x + 7 > 170 else "No")
sys.stdout.write("\n".join(out))

